import './DialogContent.scss';

import { Button } from ':components/Button';
import { useDebounceCallback } from ':helpers/use-debounce-callback';
import { useDeviceSize } from ':helpers/use-device-size';
import type { FC } from 'react';
import React, { useEffect, useRef, useState } from 'react';

import { classNames } from '../../../helpers/classnames';
import type { DialogContentProps } from './DialogContent.types';

export const DialogContent: FC<DialogContentProps> = ({
	scrollable = false,
	title,
	variant = 'desktop',
	footer,
	children,
	className,
	actions,
	fullscreen = false,
	...rest
}) => {
	const { isExtraSmallDevice } = useDeviceSize();

	// Размер кнопок для мобильных устройств должен быть medium (48px) вместо small (40px)
	const buttonSize = isExtraSmallDevice ? 'medium' : 'small';

	const defaultFooter = (
		<div className="dsb_dialog-footer_action-line">
			{actions?.cancel && (
				<Button
					className={'dsb_dialog-footer_action-button'}
					size={buttonSize}
					onClick={event => actions.cancel.onClick?.(event)}
				>
					{actions.cancel.label || 'Закрыть'}
				</Button>
			)}
			{actions?.confirm && (
				<Button
					className={'dsb_dialog-footer_action-button'}
					variant="contained"
					size={buttonSize}
					onClick={event => actions.confirm.onClick?.(event)}
				>
					{actions.confirm.label || 'Активная'}
				</Button>
			)}
		</div>
	);

	const currentFooter = footer ? footer : defaultFooter;

	const dialogChildrenRef = useRef<HTMLDivElement | null>(null);

	const [showScroll, setShowScroll] = useState<boolean>(false);

	const updateScrollable = () => {
		setShowScroll(dialogChildrenRef.current?.scrollHeight !== dialogChildrenRef.current?.clientHeight);
	};

	const [debouncedUpdatePosition] = useDebounceCallback(updateScrollable, 100);

	useEffect(() => {
		if (fullscreen) {
			return;
		}
		const onResize = () => {
			debouncedUpdatePosition();
		};
		window.addEventListener('resize', onResize);
		return () => {
			window.removeEventListener('resize', onResize);
		};
	}, []);

	useEffect(() => {
		updateScrollable();
	}, [children]);

	const fullscreenContent = (
		<div
			data-testid="DialogContent"
			className={classNames('dsb_dialog-content', className, 'dsb_dialog-content-fullscreen')}
			{...rest}
		>
			{children}
		</div>
	);
	const defaultContent = (
		<div
			data-testid="DialogContent"
			className={classNames(
				'dsb_dialog-content',
				showScroll && 'dsb_dialog-content__scrollable',
				isExtraSmallDevice && 'dsb_dialog-content__small-screen',
				className,
			)}
			{...rest}
		>
			{title && (
				<div className={classNames('dsb_dialog-title', showScroll && 'dsb_dialog-title__scrollable')}>{title}</div>
			)}

			{showScroll && <div className="dsb_dialog-divider" />}

			<div className="dsb_dialog-children" ref={dialogChildrenRef}>
				{children}
			</div>

			{showScroll && <div className="dsb_dialog-divider" />}

			{
				<div className={classNames('dsb_dialog-footer', showScroll && 'dsb_dialog-footer__scrollable')}>
					{currentFooter}
				</div>
			}
		</div>
	);

	return fullscreen ? <>{fullscreenContent}</> : <>{defaultContent}</>;
};
